from google.cloud import storage
import os, shutil
import urllib3
import json
urllib3.disable_warnings(urllib3.exceptions.InsecureRequestWarning)
 
# Cloud Function Code
def convert_and_compress(event, context):
    # Get the image file name from Cloud Storage bucket
    file = event['name']
    # Create Cloud Storage client
    storage_client = storage.Client()
 
    bucket_name = "gs://cloud-training-gcp"
    bucket = storage_client.get_bucket(bucket_name)
 
    # Obtain blob object of source file name
    imageSourceFileBlob = bucket.blob(file)
 
    # Get blob object of the same name in target directory. It is recommended to use 
    # Google Cloud Storage's eventual consistency model, so this step should happen in
    # async manner. When this step succeeds it means target file in 
    # cloud storage already exists and is ready for processing. Hence we return right away.
    imageTargetFileBlob = bucket.blob(file)
 
    if (imageTargetFileBlob != None):
        return {
            'name': 'File ' + file + ' already processed.'
        }
 
    # Set target folder name, this is where we will copy source image to
    targetFolderName = os.getenv('TARGET_FOLDER')
    if not bucket.exists(targetFolderName):
        try: 
            bucket.create_folder(targetFolderName)
        except Exception as e:
            return {
                'error': 'Error occured while creating target directory for ' + file + ': ' + str(e),
                }

    # Copy the source file to target folder
    imageTargetFileBlob = bucket.copy(source=imageSourceFileBlob, destination_name=targetFolderName + "/" + file)
 
    try:
        imageTargetFileBlob.make_public()
        imageTargetFileBlob.acl().grant_view('allUsers')
    except Exception as e:
       return {
           'error': 'Error occured while setting public view for ' + targetFolderName + "/" + file + ': ' + str(e)
         }
 
    # Create cloud storage client to access target directory files and set image target name.
    bucket = storage_client.get_bucket(bucket_name)
    imageTargetFileBlob = bucket.blob(targetFolderName + "/" + file).exists()
 
    # Get filename and convert options from Cloud Storage event metadata
    fileName = os.path.splitext(file)[0]
    extension = os.path.splitext(file)[1][-3:]
    compressionQualityPercentage = os.getenv('COMPRESSION_QUALITY')
    compressionImageType = os.getenv('IMAGE_TYPE')
 
    # Build ImageMagick convert command with image options and save output in target file
    command = ["convert", imageTargetFileBlob.public_url, "-quality", compressionQualityPercentage + "%", "-interlace", compressionImageType, "-resize", "30%", targetFolderName + "/" + fileName + ".jpeg"]
 
    # Run ImageMagick command to convert the input file using shell subprocess call
    os.chdir("/opt")
    try:
        output = shutil.call(command)
    except Exception as e:
        return {
            'error': 'Error occured while running convert command for image in cloud storage: ' + str(e),
         }
 
    # Delete source file from Cloud Storage bucket
    bucket.delete_blob(file)
 
    # Make target file public accessible to the world with Google’s default ACL
    try:
        imageTargetFileBlob = bucket.get_blob(targetFolderName + "/" + fileName + ".jpeg")
        imageTargetFileBlob.acl().grant_public_access('READER')
        return {
            'name': 'Successfully processed image in cloud storage.',
         }
 
    except Exception as e:
       return {
           'error': 'Error occured while setting public view for target file in cloud storage.: ' + str(e)
    }

